changeSet.sql:
ALTER TABLE nexus.ladder_completions ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.ladder_completions FORCE ROW LEVEL SECURITY;

-- cmd=ALL: covers SELECT, INSERT, UPDATE, DELETE in one policy.
-- current_setting('nexus.tenant', true): missing_ok=true so unset GUC returns NULL
--   rather than raising. NULL != any tenant_id -> zero rows visible = fail-closed.
CREATE POLICY tenant_isolation ON nexus.ladder_completions
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.ladder_completions;
ALTER TABLE nexus.ladder_completions NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.ladder_completions DISABLE ROW LEVEL SECURITY;
